const Q_ECONOMICS_2017_MODEL_II=[{"id": "objective>Economics>2017 Model II>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following are forms of agricultural system in West Africa except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Subsistence agricultural production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Production of farm implement and fertilizer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Peasant agricultural product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Plantation agricultural system</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The question asks for forms of agricultural systems in West Africa, and 'Production of farm implement and fertilizer' does not represent an agricultural system but rather a component of agricultural production. The other options are recognized forms of agricultural systems.</div>", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES"}, {"id": "objective>Economics>2017 Model II>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">All graphical representations must have</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">two axes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">zero origin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">graduation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">all of the above</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">All graphical representations in economics must have two axes, a zero origin, and graduation. These elements are necessary for accurately depicting data and relationships in economic graphs.</div>", "topic": "METHODS OF ECONOMIC ANALYSIS"}, {"id": "objective>Economics>2017 Model II>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the reasons why government impose trade barriers is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Control foreign currencies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Protec infant industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Promote importation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Diversify the economy</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the reasons governments impose trade barriers is to protect infant industries. This means that new or emerging industries in a country may need protection from foreign competition until they become established and can compete on their own. Trade barriers can take the form of tariffs, quotas, or subsidies.</div>", "topic": "INTERNATIONAL TRADE : INTRODUCTION"}, {"id": "objective>Economics>2017 Model II>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following taxes is an example of regressive tax?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Income tax</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Custom tax</div>", "<div style=\"font-family:Cambria;font-size:17px;\">poll tax</div>", "<div style=\"font-family:Cambria;font-size:17px;\">direct tax</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A regressive tax is one where the tax rate decreases as the taxable amount increases, meaning that lower-income individuals pay a higher percentage of their income compared to higher-income individuals. Among the options provided, a 'poll tax' is a classic example of a regressive tax because it charges the same amount regardless of income, disproportionately affecting those with lower incomes. In contrast, income tax is typically progressive, custom tax can vary, and direct tax can include both progressive and regressive elements.</div>", "topic": "PUBLIC FINANCE : CLASSIFICATION OF TAX"}, {"id": "objective>Economics>2017 Model II>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Under conditions of perfect competition in the product market</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">MRP = VMP</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MRP >VMP</div>", "<div style=\"font-family:Cambria;font-size:17px;\">VMP > MRP</div>", "<div style=\"font-family:Cambria;font-size:17px;\">None of the above</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Under conditions of perfect competition in the product market, the marginal revenue product (MRP) equals the value of marginal product (VMP). This equality occurs because firms in perfect competition can sell additional units of output at the market price, leading to MRP being equal to VMP, which reflects the additional revenue generated from employing one more unit of a factor of production.</div>", "topic": "MARKET STRUCTURE : PERFECT MARKET"}, {"id": "objective>Economics>2017 Model II>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which among the following is NOT an assumption of Pareto optimality?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Every consumer wishes to maximize his level of satisfaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">All the factors of production are used in the production of every commodity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Conditions of perfect competition exist making all the factors of production perfectly mobile</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The concept of utility is cardinal and cardinal utility function of every consumer is given</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the assumptions of Pareto optimality is that all factors of production are used efficiently in the production of goods. The statement that 'All the factors of production are used in the production of every commodity' is not a correct assumption, as Pareto efficiency does not require that all resources be used in every commodity's production, but rather that resources are allocated in a way that no one can be made better off without making someone else worse off.</div>", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM"}, {"id": "objective>Economics>2017 Model II>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is true about import -substitution ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It helps in increasing exportation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Is meant to reduce exportation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It enables a country to improve importation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It enables a country to curtail importation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Import-substitution is an economic policy aimed at reducing dependency on foreign imports by promoting domestic production. Therefore, it enables a country to curtail importation by fostering local industries.</div>", "topic": "INTERNATIONAL TRADE : INTRODUCTION"}, {"id": "objective>Economics>2017 Model II>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following market structure is the degree of control over the price of its product by a firm very large?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Imperfect competition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Perfect competition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Monopoly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">In A and B both</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a monopoly market structure, a single firm has significant control over the price of its product because it is the sole provider of that good or service. Unlike perfect competition, where many firms compete and have no control over prices, a monopolist can set prices above marginal cost to maximize profits, leading to a higher degree of price control.</div>", "topic": "MARKET STRUCTURE"}, {"id": "objective>Economics>2017 Model II>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following will not retard economic development in West Africa ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Dependence on imports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Population control </div>", "<div style=\"font-family:Cambria;font-size:17px;\">High level of illiteracy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Low level of saving</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Population control is not a factor that would retard economic development in West Africa. In fact, effective population control can lead to better resource allocation and economic growth, while dependence on imports, high illiteracy, and low savings are known to hinder development.</div>", "topic": "ECONOMIC DEVELOPMENT : INTRODUCTION"}, {"id": "objective>Economics>2017 Model II>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Net National income is national income less</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">subsidies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">indirect taxes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">depreciation allowance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transfer payments</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Net National Income (NNI) is calculated by subtracting 'depreciation allowance' from National Income. Depreciation accounts for the loss of value of capital goods over time, ensuring that the income reflects the actual economic output.</div>", "topic": "NATIONAL INCOME : CONCEPT"}, {"id": "objective>Economics>2017 Model II>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Opportunity cost is best defined as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the amount given up when choosing one activity over all other alternatives</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the amount given up when choosing one activity over the next best alternative</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the opportunity to earn a profit that is greater than one currently being made</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the amount that is given up when choosing an activity that is not as good as the next best alternative</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Opportunity cost is best defined as the amount given up when choosing one activity over the next best alternative. This concept highlights the trade-offs involved in decision-making, where the cost of a chosen option is the value of the best alternative that is forgone.</div>", "topic": "BASIC CONCEPTS OF ECONOMICS"}, {"id": "objective>Economics>2017 Model II>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Diminishing marginal utility means that total utility</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rises at a decreasing rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diminishing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fall, then rises</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rises at an increasing rate</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diminishing marginal utility refers to the principle that as a person consumes more units of a good, the additional satisfaction (utility) gained from each additional unit decreases. Therefore, total utility rises at a decreasing rate.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : DIMINISHING MARGINAL UTILITY AND LAW OF DEMAND"}, {"id": "objective>Economics>2017 Model II>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Most of the underdeveloped economies suffer from ...................... which do not let the rate of growth go up from a lower level</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">High population pressures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">High infant mortality</div>", "<div style=\"font-family:Cambria;font-size:17px;\">High monetary mismanagement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">High level of technological unemployment</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Underdeveloped economies often suffer from high population pressures, which can strain resources and limit economic growth. High population growth can lead to increased demand for jobs, education, and healthcare, which may not be met by the economy, thus hindering growth.</div>", "topic": "ECONOMIC DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT"}, {"id": "objective>Economics>2017 Model II>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Cost push inflation occurs because of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Wage push</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Profit push</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Both A and B</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ineffective policies of the government</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cost-push inflation occurs due to increases in the cost of production, which can be caused by wage push (increased wages) and profit push (increased profit margins). Therefore, both A and B are correct, making 'Both A and B' the right answer.</div>", "topic": "INFLATION"}, {"id": "objective>Economics>2017 Model II>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which among the following is not a function of International Monetary Fund?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It serves a medium term and long term credit institution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It provides a mechanism for improving short term balance of payments position</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It provides machinery for international consultations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It provides reservoir of the currencies of the member countries and enables members to borrow one another's currency</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The International Monetary Fund (IMF) primarily provides short-term financial assistance and does not serve as a medium or long-term credit institution. Its main functions include providing temporary financial support to countries facing balance of payments problems and facilitating international monetary cooperation.</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IMF"}, {"id": "objective>Economics>2017 Model II>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A demand curve can shift because of changing</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Prices of related goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Taste</div>", "<div style=\"font-family:Cambria;font-size:17px;\">All of the above</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A demand curve can shift due to various factors, including changes in income, prices of related goods (substitutes and complements), and consumer tastes. Therefore, the correct answer is 'All of the above' as all these factors can lead to a shift in the demand curve.</div>", "topic": "THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2017 Model II>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At point of satiety, marginal utility is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">zero</div>", "<div style=\"font-family:Cambria;font-size:17px;\">positive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">maximum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">negative</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">At the point of satiety, a consumer has consumed enough of a good that they no longer desire more. This results in the marginal utility, which is the additional satisfaction from consuming one more unit, being zero.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONCEPT"}, {"id": "objective>Economics>2017 Model II>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If MPC is equal to 0.7, what is the value of MPS?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.13</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.30</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">MPC (Marginal Propensity to Consume) and MPS (Marginal Propensity to Save) are related by the equation MPC + MPS = 1. If MPC is 0.7, then MPS = 1 - 0.7 = 0.3. Thus, the correct answer is option 4.</div>", "topic": "BASIC CONCEPTS OF ECONOMICS"}, {"id": "objective>Economics>2017 Model II>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> What is the equilibrium price and quantity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5, 55</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5, 65</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10, 75</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10, 65</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Equilibrium price is the price where demand equates supply. From the diagram above, equilibrium price is 10 at the point of intersection while the equilibrium quantity is 65.</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : INTRODUCTION"}, {"id": "objective>Economics>2017 Model II>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the diagram below, the line labelled PM is the marginal revenue curve of a  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">monopoly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">competitive firm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">monopsony</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oligopoly</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The line labeled PM in the diagram is the marginal revenue curve of a monopoly. <br/>  <br/> A monopoly is a firm that is the sole supplier of a good or service in a market. This gives the monopoly firm a significant degree of market power, which it can use to set prices and output. <br/>  <br/> The marginal revenue curve for a monopoly firm is always below the demand curve for its product. This is because the monopoly firm has to reduce the price of its product to sell more units. <br/>  <br/> The diagram shows the demand curve for a monopoly firm (D) and its marginal revenue curve (MR). The demand curve is downward sloping, which indicates that the quantity demanded of the good decreases as the price increases. The marginal revenue curve is also downward sloping, but it is below the demand curve.</div>", "topic": "MARKET STRUCTURE"}, {"id": "objective>Economics>2017 Model II>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A budget where current receipts are less then current expenditure is called ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Balanced budget</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Unbalanced budget</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Deficit budget</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Surplus budget</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A budget where current receipts are less than current expenditure is known as a 'Deficit budget'. This indicates that the government is spending more than it is earning, leading to a budget deficit.</div>", "topic": "PUBLIC FINANCE"}, {"id": "objective>Economics>2017 Model II>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A market structure in which free entry and exit exist and all the sellers are price taker is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Monopoly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Monopolistic competition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Duopoly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A perfect competition</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A market structure where free entry and exit exist, and all sellers are price takers is known as perfect competition. In perfect competition, numerous small firms compete against each other, and no single firm can influence the market price. This is characterized by homogeneous products and the inability of any single seller to set prices.</div>", "topic": "MARKET STRUCTURE : PERFECT MARKET"}, {"id": "objective>Economics>2017 Model II>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a normal chain of distribution ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Producer ------- Wholesaler ------- Retailer -------- Consumer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Producer --------- Manager -------- Consumer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Producer ---------- Wholesaler -------- Consumer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Producer ----------Consumer</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The option 'Producer --------- Manager -------- Consumer' does not represent a normal chain of distribution. In a typical distribution chain, goods move from producers to wholesalers, then to retailers, and finally to consumers. The presence of a 'Manager' in the chain is not standard and does not fit the conventional distribution model.</div>", "topic": "DISTRIBUTIVE TRADE : THE MIDDLEMEN"}, {"id": "objective>Economics>2017 Model II>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What happens to marginal cost when average cost increases</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Marginal cost is below average cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Marginal cost is above average cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Marginal cost is equal to average variable cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Marginal cost is equal to average cost</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When average cost increases, it typically indicates that the cost of producing additional units is higher than the average cost of previous units. Therefore, marginal cost, which is the cost of producing one more unit, will be above the average cost. This relationship is a fundamental concept in economics, where marginal cost intersects with average cost at the minimum point of the average cost curve. Hence, the correct answer is 'Marginal cost is above average cost'.</div>", "topic": "THEORY OF COST AND REVENUE"}, {"id": "objective>Economics>2017 Model II>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which statistical measure helps in measuring the purchasing power of money?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Arithmetic average</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Index numbers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Harmonic mean</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Time series</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The purchasing power of money is typically measured using index numbers, such as the Consumer Price Index (CPI) or the Producer Price Index (PPI). These indices track changes in the price level of a basket of goods and services over time, allowing economists to assess how much a unit of currency can buy at different points in time.</div>", "topic": "BASIC CONCEPTS OF ECONOMICS"}, {"id": "objective>Economics>2017 Model II>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A review of occupational distribution of population from time to time helps us to know the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rate of which the population grows</div>", "<div style=\"font-family:Cambria;font-size:17px;\">number of people that makes up the labour force</div>", "<div style=\"font-family:Cambria;font-size:17px;\">efficiency of the working population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">industries which are becoming less important</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A review of occupational distribution helps to understand the efficiency of the working population. By analyzing how the population is distributed across various occupations, we can assess how effectively the labor force is utilized. Thus, the correct option is 'efficiency of the working population'.</div>", "topic": "POPULATION"}, {"id": "objective>Economics>2017 Model II>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Cost of raw materials in production is an example of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">marginal cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">variable cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fixed cost</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The cost of raw materials in production is an example of 'variable cost'. Variable costs change with the level of output; as production increases, the cost of raw materials increases. In contrast, fixed costs remain constant regardless of production levels.</div>", "topic": "THEORY OF COST AND REVENUE"}, {"id": "objective>Economics>2017 Model II>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A free market economy operates when</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the forces of supply and demand apply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is free entry and exit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is government intervention</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a capitalist economy is operated</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A free market economy operates when the forces of supply and demand apply without government intervention. In such an economy, prices are determined by the market, and resources are allocated based on consumer preferences and producer costs.</div>", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM"}, {"id": "objective>Economics>2017 Model II>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following cases is assumption most reasonable in economics?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">to address the impact of taxes on income distribution, an economist assumes that everyone earns the same income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">to address the impact of money growth on inflation, an economist assumes that money is strictly coins</div>", "<div style=\"font-family:Cambria;font-size:17px;\">to model the benefits of trade, an economist assumes that there are two people and two goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">to estimate the speed at which a beach ball falls, a physicist assumes that it falls in a vacuum</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The assumption that there are two people and two goods is a simplification that allows economists to model the benefits of trade effectively. This assumption is reasonable because it simplifies the complex interactions in an economy, making it easier to analyze the fundamental principles of trade.</div>", "topic": "THE THEORY OF DEMAND"}, {"id": "objective>Economics>2017 Model II>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Demand for factors of production is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Derived demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Joint demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Composite demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">None of the above</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Demand for factors of production is referred to as derived demand. This means that the demand for these factors is dependent on the demand for the goods and services they help to produce. For example, if the demand for cars increases, the demand for labor and materials to produce those cars will also increase.</div>", "topic": "FACTORS OF PRODUCTION AND THEIR THEORIES"}, {"id": "objective>Economics>2017 Model II>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Select the group that best represents the basic factors of production</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">land, labour, capital and entreprenuership</div>", "<div style=\"font-family:Cambria;font-size:17px;\">land, labour, money, management skills</div>", "<div style=\"font-family:Cambria;font-size:17px;\">land, natural resources, labour , capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">land, labour, capital , technology</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The basic factors of production are traditionally classified into four categories: land, labour, capital, and entrepreneurship. These factors are essential for the production of goods and services in an economy. Therefore, the correct answer is the group that includes land, labour, capital, and entrepreneurship.</div>", "topic": "FACTORS OF PRODUCTION AND THEIR THEORIES"}, {"id": "objective>Economics>2017 Model II>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The best definition of economics is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">how choices are made under conditions of scarcity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">how money is used</div>", "<div style=\"font-family:Cambria;font-size:17px;\">how goods and services are produced </div>", "<div style=\"font-family:Cambria;font-size:17px;\">how businesses maximize profit</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The best definition of economics is how choices are made under conditions of scarcity. Economics fundamentally deals with the allocation of limited resources to meet unlimited wants, which is encapsulated in the concept of scarcity.</div>", "topic": "BASIC CONCEPTS OF ECONOMICS"}, {"id": "objective>Economics>2017 Model II>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the labour force of a country is 2.5 million and 2 million are employed, what is the unemployment rate ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.2%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">200%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">250%</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The unemployment rate is calculated as the number of unemployed individuals divided by the total labor force, multiplied by 100. In this case, the labor force is 2.5 million, and if 2 million are employed, then 0.5 million are unemployed. The unemployment rate is (0.5 million / 2.5 million) * 100 = 20%.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT"}, {"id": "objective>Economics>2017 Model II>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When the population growth rate of an economy becomes greater than the achievable economic growth rate, it is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Population explosion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Population trap</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Population crisis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">None of the above</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When the population growth rate exceeds the achievable economic growth rate, it is referred to as a 'Population trap'. This situation can lead to increased poverty and unemployment, as the economy cannot support the growing population. The other options do not accurately describe this phenomenon.</div>", "topic": "POPULATION : THEORIES OF POPULATION"}, {"id": "objective>Economics>2017 Model II>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">For measuring the changes in the price level of the country, which among the following index number is used?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cost of living index number</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Production index number</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Security price index number</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Wholesale price index number</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To measure changes in the price level of a country, the 'Cost of living index number' is commonly used. This index reflects the changes in the price of a basket of goods and services typically consumed by households. The other options do not specifically measure the overall price level changes.</div>", "topic": "INFLATION & DEFLATION : INTRODUCTION"}, {"id": "objective>Economics>2017 Model II>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Industrialization helps to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase the level of employment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">boost the agricultural sector</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A and B</div>", "<div style=\"font-family:Cambria;font-size:17px;\">None of the above</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Industrialization helps to increase the level of employment by creating jobs in factories and industries. It can also boost the agricultural sector by providing better tools and technology, thus both options A and B are correct.</div>", "topic": "INDUSTRY AND INDUSTRIALIZATION"}, {"id": "objective>Economics>2017 Model II>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which among the following statement is INCORRECT?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">On a linear demand curve, all the five forms of elasticity can be depicted</div>", "<div style=\"font-family:Cambria;font-size:17px;\">If two demand curves are linear and intersecting each other then coefficient of elasticity would be same on different demand curves at the point of intersection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">If two demand curves are linear, and parallel to each other then at a particular price the coefficient of elasticity would be different on different demand curves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The price elasticity of demand is expressed in terms of relative not absolute, changes in price and quantity demanded</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The statement that is INCORRECT is that if two demand curves are linear and parallel to each other, then at a particular price, the coefficient of elasticity would be different on different demand curves. In fact, if the demand curves are parallel, the price elasticity of demand will be the same at any given price level. Therefore, this statement is incorrect.</div>", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2017 Model II>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When the negative income effect is greater than substitution effect, it is the case of which one of the following?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Giffen goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Inferior goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Luxury goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Normal goods</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Giffen goods are a special type of inferior goods for which an increase in the price leads to an increase in quantity demanded, due to the negative income effect outweighing the substitution effect. This is a unique case in consumer theory.</div>", "topic": "THEORY OF DEMAND : TYPES OF DEMAND"}, {"id": "objective>Economics>2017 Model II>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major characteristic of money is it is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Relatively scarcity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Portability</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Durability</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Acceptability</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The major characteristic of money is its 'Acceptability'. Money must be widely accepted as a medium of exchange for it to function effectively in an economy. While portability, durability, and relative scarcity are important characteristics, acceptability is fundamental to the use of money.</div>", "topic": "MONEY"}, {"id": "objective>Economics>2017 Model II>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Total product refers to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">total amount of goods produce over a period of time by all factors of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total amount of goods produce over a period of time by non specific factor of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total amount of food produce over a period of time by specific factor of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">none of the above</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Total product refers to the total amount of goods produced over a period of time by all factors of production. It includes the contributions of both specific and non-specific factors of production. Total product represents the aggregate output or total quantity of goods produced by utilizing all available inputs, regardless of their specificity. Therefore, the correct option is the first one you mentioned: \"total amount of goods produced over a period of time by all factors of production.\"</div>", "topic": "FACTORS OF PRODUCTION AND THEIR THEORIES"}];
